import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateWeddingQuote(groom: string, bride: string): Promise<string> {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Hãy viết một câu danh ngôn tình yêu lãng mạn cho đám cưới của ${groom} và ${bride} bằng tiếng Việt. Ngắn gọn, súc tích, ý nghĩa. Chỉ trả về đúng câu nói.`,
    });
    return response.text || "Tình yêu là chìa khóa mở cánh cửa hạnh phúc.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Hạnh phúc không phải là đích đến, mà là hành trình chúng ta đi cùng nhau.";
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { WeddingData, RSVP } from './types';
import { DEFAULT_WEDDING_DATA, HeartIcon, TraditionalBorder } from './constants';
import { generateWeddingQuote } from './geminiService';

const App: React.FC = () => {
  const [data, setData] = useState<WeddingData>(DEFAULT_WEDDING_DATA);
  const [aiQuote, setAiQuote] = useState<string>("");
  const [loadingQuote, setLoadingQuote] = useState(false);
  const [rsvp, setRsvp] = useState<RSVP>({ name: '', attendance: 'yes', guests: 1, message: '' });
  const [showRsvpSuccess, setShowRsvpSuccess] = useState(false);
  const [timeLeft, setTimeLeft] = useState<{ d: number; h: number; m: number; s: number }>({ d: 0, h: 0, m: 0, s: 0 });

  // Countdown logic
  useEffect(() => {
    const target = new Date(data.date).getTime();
    const interval = setInterval(() => {
      const now = new Date().getTime();
      const distance = target - now;
      if (distance < 0) {
        clearInterval(interval);
        return;
      }
      setTimeLeft({
        d: Math.floor(distance / (1000 * 60 * 60 * 24)),
        h: Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
        m: Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60)),
        s: Math.floor((distance % (1000 * 60)) / 1000)
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [data.date]);

  const handleGenerateQuote = async () => {
    setLoadingQuote(true);
    const quote = await generateWeddingQuote(data.groomName, data.brideName);
    setAiQuote(quote);
    setLoadingQuote(false);
  };

  const handleRsvpSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Simulate API call
    setTimeout(() => {
      setShowRsvpSuccess(true);
      setRsvp({ name: '', attendance: 'yes', guests: 1, message: '' });
      setTimeout(() => setShowRsvpSuccess(false), 5000);
    }, 800);
  };

  return (
    <div className="min-h-screen max-w-[500px] mx-auto bg-white shadow-2xl relative">
      {/* Hero Section */}
      <section className="relative h-screen flex flex-col items-center justify-end overflow-hidden">
        <div className="absolute inset-0 z-0">
          <img 
            src={data.heroImage} 
            alt="Wedding Hero" 
            className="w-full h-full object-cover brightness-75 transition-all duration-700 hover:scale-105"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-red-900/60 via-transparent to-transparent"></div>
        </div>

        <div className="relative z-10 text-center text-white pb-20 px-6">
          <h2 className="text-xl uppercase tracking-[0.2em] mb-4 font-light drop-shadow-lg">Trân Trọng Kính Mời</h2>
          <div className="flex flex-col items-center gap-2">
            <h1 className="text-5xl font-wedding leading-tight drop-shadow-xl">{data.groomName}</h1>
            <HeartIcon />
            <h1 className="text-5xl font-wedding leading-tight drop-shadow-xl">{data.brideName}</h1>
          </div>
          <p className="mt-8 text-lg font-medium tracking-widest bg-red-600/40 backdrop-blur-sm py-2 px-4 rounded-full border border-red-200/50">
            {new Date(data.date).toLocaleDateString('vi-VN', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
          </p>
        </div>
      </section>

      {/* Intro Section */}
      <section className="py-16 px-8 text-center bg-pattern">
        <TraditionalBorder />
        <p className="text-gray-600 italic leading-relaxed mb-6">
          "Đường chúng ta đi sẽ không bao giờ vắng bóng nhau. <br/>Hạnh phúc là khi được nắm tay người mình yêu đi trọn cuộc đời."
        </p>

        {aiQuote && (
          <div className="my-6 p-4 bg-red-50 border-l-4 border-red-600 rounded-r-lg animate-fade-in">
            <p className="text-red-800 font-medium italic">"{aiQuote}"</p>
          </div>
        )}

        <button 
          onClick={handleGenerateQuote}
          disabled={loadingQuote}
          className="text-xs text-red-600 hover:text-red-800 transition-all uppercase tracking-widest font-bold flex items-center justify-center gap-2 mx-auto"
        >
          {loadingQuote ? 'Đang tạo cảm hứng...' : '✨ Tạo câu châm ngôn tình yêu'}
        </button>
      </section>

      {/* Details Section */}
      <section className="py-16 px-6 bg-red-600 text-white rounded-t-[40px] -mt-10 relative z-20">
        <div className="text-center mb-10">
          <h2 className="text-3xl font-wedding mb-2">Thông Tin Buổi Tiệc</h2>
          <div className="h-1 w-20 bg-white/30 mx-auto rounded-full"></div>
        </div>

        <div className="space-y-8">
          <div className="flex items-start gap-4 p-4 bg-white/10 rounded-2xl backdrop-blur-sm border border-white/20">
            <div className="bg-white text-red-600 p-2 rounded-lg">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
            </div>
            <div>
              <h3 className="font-bold text-lg">Thời Gian</h3>
              <p className="opacity-90">{data.time}, Ngày {new Date(data.date).toLocaleDateString('vi-VN')}</p>
            </div>
          </div>

          <div className="flex items-start gap-4 p-4 bg-white/10 rounded-2xl backdrop-blur-sm border border-white/20">
            <div className="bg-white text-red-600 p-2 rounded-lg">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
            </div>
            <div>
              <h3 className="font-bold text-lg">Địa Điểm</h3>
              <p className="opacity-90 leading-snug">{data.location}</p>
              <a 
                href="https://maps.app.goo.gl/..." 
                target="_blank" 
                rel="noopener noreferrer"
                className="inline-block mt-3 text-sm underline font-medium hover:text-gray-200"
              >
                Xem Bản Đồ →
              </a>
            </div>
          </div>
        </div>

        {/* Countdown */}
        <div className="mt-12 grid grid-cols-4 gap-4 text-center">
          {[
            { label: 'Ngày', val: timeLeft.d },
            { label: 'Giờ', val: timeLeft.h },
            { label: 'Phút', val: timeLeft.m },
            { label: 'Giây', val: timeLeft.s },
          ].map((item, i) => (
            <div key={i} className="bg-white/10 rounded-xl p-2 border border-white/10 backdrop-blur-md">
              <div className="text-2xl font-bold">{item.val}</div>
              <div className="text-[10px] uppercase tracking-wider opacity-70">{item.label}</div>
            </div>
          ))}
        </div>
      </section>

      {/* Album Section */}
      <section className="py-16 bg-white">
        <div className="px-6 mb-8 flex items-end justify-between">
          <div>
            <h2 className="text-3xl font-wedding text-red-600">Album Ảnh</h2>
            <p className="text-gray-400 text-sm">Những khoảnh khắc ngọt ngào</p>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-2 px-2">
          {data.album.map((img, idx) => (
            <div key={idx} className={`overflow-hidden rounded-lg ${idx % 3 === 0 ? 'row-span-2' : ''}`}>
              <img 
                src={img} 
                alt={`Wedding ${idx}`} 
                className="w-full h-full object-cover transition-transform duration-500 hover:scale-110 active:scale-95 cursor-pointer"
                loading="lazy"
              />
            </div>
          ))}
        </div>
      </section>

      {/* RSVP Section */}
      <section className="py-20 px-8 bg-gray-50 border-t border-gray-100">
        <div className="text-center mb-10">
          <TraditionalBorder />
          <h2 className="text-3xl font-wedding text-red-600 mb-2">Xác Nhận Tham Dự</h2>
          <p className="text-gray-500 text-sm">Để chúng tôi tiếp đón chu đáo nhất</p>
        </div>

        <form onSubmit={handleRsvpSubmit} className="space-y-6">
          <div>
            <label className="block text-xs font-bold uppercase text-gray-500 mb-2 ml-1">Tên Của Bạn</label>
            <input 
              required
              type="text" 
              placeholder="Vui lòng nhập họ tên"
              value={rsvp.name}
              onChange={e => setRsvp({...rsvp, name: e.target.value})}
              className="w-full bg-white border border-gray-200 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-red-500 focus:border-transparent transition-all shadow-sm"
            />
          </div>

          <div className="flex gap-4">
            <button 
              type="button"
              onClick={() => setRsvp({...rsvp, attendance: 'yes'})}
              className={`flex-1 py-3 rounded-xl border font-bold transition-all ${rsvp.attendance === 'yes' ? 'bg-red-600 text-white border-red-600 shadow-lg' : 'bg-white text-gray-400 border-gray-200'}`}
            >
              Tham Dự
            </button>
            <button 
              type="button"
              onClick={() => setRsvp({...rsvp, attendance: 'no'})}
              className={`flex-1 py-3 rounded-xl border font-bold transition-all ${rsvp.attendance === 'no' ? 'bg-gray-800 text-white border-gray-800 shadow-lg' : 'bg-white text-gray-400 border-gray-200'}`}
            >
              Rất Tiếc
            </button>
          </div>

          <div>
            <label className="block text-xs font-bold uppercase text-gray-500 mb-2 ml-1">Số Lượng Khách</label>
            <select 
              value={rsvp.guests}
              onChange={e => setRsvp({...rsvp, guests: parseInt(e.target.value)})}
              className="w-full bg-white border border-gray-200 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-red-500 transition-all shadow-sm"
            >
              {[1, 2, 3, 4, 5].map(n => <option key={n} value={n}>{n} người</option>)}
            </select>
          </div>

          <div>
            <label className="block text-xs font-bold uppercase text-gray-500 mb-2 ml-1">Lời Chúc (Tùy Chọn)</label>
            <textarea 
              rows={3}
              placeholder="Gửi lời chúc đến cô dâu & chú rể..."
              value={rsvp.message}
              onChange={e => setRsvp({...rsvp, message: e.target.value})}
              className="w-full bg-white border border-gray-200 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-red-500 transition-all shadow-sm"
            ></textarea>
          </div>

          <button 
            type="submit"
            className="w-full bg-red-600 hover:bg-red-700 text-white font-bold py-4 rounded-xl shadow-xl transition-all transform active:scale-95 flex items-center justify-center gap-2"
          >
            Gửi Xác Nhận
          </button>
        </form>

        {showRsvpSuccess && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-black/40 backdrop-blur-sm">
            <div className="bg-white rounded-3xl p-8 text-center shadow-2xl animate-scale-in max-w-xs">
              <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
                <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg>
              </div>
              <h3 className="text-xl font-bold mb-2">Đã Nhận Thông Tin!</h3>
              <p className="text-gray-500 text-sm">Cảm ơn bạn đã xác nhận tham dự. Hẹn gặp lại tại buổi tiệc!</p>
              <button 
                onClick={() => setShowRsvpSuccess(false)}
                className="mt-6 w-full py-2 bg-gray-100 rounded-lg text-gray-600 font-medium"
              >
                Đóng
              </button>
            </div>
          </div>
        )}
      </section>

      {/* Footer */}
      <footer className="py-12 bg-white text-center border-t border-gray-100">
        <p className="text-red-600 font-wedding text-2xl mb-4">Thank You</p>
        <p className="text-gray-400 text-xs px-12 leading-loose">
          Rất hân hạnh được đón tiếp bạn <br/> trong ngày vui của gia đình chúng tôi!
        </p>
        <div className="mt-8 opacity-20">
          <TraditionalBorder />
        </div>
      </footer>

      {/* Floating Music Toggle (Mock) */}
      <div className="fixed bottom-6 right-6 z-50">
        <button className="bg-white/80 backdrop-blur-md p-3 rounded-full shadow-lg border border-gray-100 text-red-600 animate-pulse">
           <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M12 3v10.55c-.59-.34-1.27-.55-2-.55-2.21 0-4 1.79-4 4s1.79 4 4 4 4-1.79 4-4V7h4V3h-6z"/></svg>
        </button>
      </div>
    </div>
  );
};

