import React, { useState, useEffect } from 'react';
import { WeddingData, RSVP } from './types';
import { DEFAULT_WEDDING_DATA, HeartIcon, TraditionalBorder, FloralDecoration, CONFIG } from './constants';
import { generateWeddingQuote } from './geminiService';

const App: React.FC = () => {
  const [data] = useState<WeddingData>(DEFAULT_WEDDING_DATA);
  const [aiQuote, setAiQuote] = useState<string>("");
  const [loadingQuote, setLoadingQuote] = useState(false);
  const [submittingRsvp, setSubmittingRsvp] = useState(false);
  const [rsvp, setRsvp] = useState<RSVP>({ name: '', attendance: 'yes', guests: 1, message: '' });
  const [showRsvpSuccess, setShowRsvpSuccess] = useState(false);
  const [showGift, setShowGift] = useState(false);
  const [timeLeft, setTimeLeft] = useState({ d: 0, h: 0, m: 0, s: 0 });

  useEffect(() => {
    const target = new Date(data.date).getTime();
    const interval = setInterval(() => {
      const now = new Date().getTime();
      const distance = target - now;
      if (distance < 0) {
        clearInterval(interval);
        return;
      }
      setTimeLeft({
        d: Math.floor(distance / (1000 * 60 * 60 * 24)),
        h: Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
        m: Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60)),
        s: Math.floor((distance % (1000 * 60)) / 1000)
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [data.date]);

  const handleGenerateQuote = async () => {
    if (loadingQuote) return;
    setLoadingQuote(true);
    const quote = await generateWeddingQuote(data.groomName, data.brideName);
    setAiQuote(quote);
    setLoadingQuote(false);
  };

  const handleRsvpSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmittingRsvp(true);

    // Gửi thông báo qua Telegram nếu được cấu hình
    if (CONFIG.useTelegram && CONFIG.telegramToken && CONFIG.telegramChatId) {
      const text = `🔔 *XÁC NHẬN THAM DỰ MỚI*\n\n👤 Khách: ${rsvp.name}\n✅ Trạng thái: ${rsvp.attendance === 'yes' ? 'SẼ THAM DỰ' : 'RẤT TIẾC'}\n👥 Số lượng: ${rsvp.guests} người\n💌 Lời chúc: ${rsvp.message || 'Không có'}`;

      try {
        await fetch(`https://api.telegram.org/bot${CONFIG.telegramToken}/sendMessage`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            chat_id: CONFIG.telegramChatId,
            text: text,
            parse_mode: 'Markdown'
          })
        });
      } catch (error) {
        console.error("Lỗi gửi Telegram:", error);
      }
    }

    setSubmittingRsvp(false);
    setShowRsvpSuccess(true);
    // Reset form
    setRsvp({ name: '', attendance: 'yes', guests: 1, message: '' });
  };

  return (
    <div className="min-h-screen max-w-[500px] mx-auto bg-white shadow-2xl relative">
      {/* Hero Cover */}
      <section className="relative h-[90vh] flex items-center justify-center overflow-hidden">
        <div className="absolute inset-0 z-0">
          <img 
            src={data.heroImage} 
            alt="Wedding Cover" 
            className="w-full h-full object-cover brightness-[0.85]"
          />
          <div className="absolute inset-0 bg-gradient-to-b from-black/20 via-transparent to-red-900/40"></div>
        </div>

        <div className="relative z-10 text-center text-white px-6 animate-fade-up">
          <p className="text-sm uppercase tracking-[0.4em] mb-4 font-medium opacity-90">Wedding Invitation</p>
          <div className="mb-6">
            <h1 className="text-6xl font-wedding leading-tight drop-shadow-lg">{data.groomName.split(' ').pop()}</h1>
            <div className="flex items-center justify-center gap-4 my-2">
              <div className="h-[1px] w-8 bg-white/50"></div>
              <HeartIcon className="text-white w-5 h-5" />
              <div className="h-[1px] w-8 bg-white/50"></div>
            </div>
            <h1 className="text-6xl font-wedding leading-tight drop-shadow-lg">{data.brideName.split(' ').pop()}</h1>
          </div>
          <div className="inline-block border border-white/40 px-6 py-2 rounded-full backdrop-blur-sm">
            <p className="text-lg tracking-widest font-light">
              {new Date(data.date).toLocaleDateString('vi-VN', { day: '2-digit', month: '2-digit', year: 'numeric' })}
            </p>
          </div>
        </div>
      </section>

      {/* Formal Invitation Section */}
      <section className="py-20 px-8 text-center bg-pattern relative">
        <div className="absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2">
           <div className="bg-white p-3 rounded-full shadow-lg border border-red-50">
              <HeartIcon className="text-red-500" />
           </div>
        </div>

        <div className="space-y-6">
          <h3 className="text-red-600 font-serif-elegant italic text-2xl">Trân Trọng Kính Mời</h3>
          <p className="text-gray-500 uppercase tracking-widest text-[10px] font-bold">Tới dự lễ thành hôn của chúng tôi</p>

          <div className="grid grid-cols-2 gap-8 py-8 items-center">
            <div className="text-right">
              <p className="font-bold text-gray-800">{data.groomName}</p>
              <p className="text-[10px] text-gray-400 mt-1 uppercase">Thứ Nam</p>
              <div className="mt-4 text-[11px] text-gray-500 leading-relaxed">
                <p>Ông: {data.groomFather}</p>
                <p>Bà: {data.groomMother}</p>
              </div>
            </div>
            <div className="text-left border-l border-gray-100 pl-8">
              <p className="font-bold text-gray-800">{data.brideName}</p>
              <p className="text-[10px] text-gray-400 mt-1 uppercase">Ái Nữ</p>
              <div className="mt-4 text-[11px] text-gray-500 leading-relaxed">
                <p>Ông: {data.brideFather}</p>
                <p>Bà: {data.brideMother}</p>
              </div>
            </div>
          </div>

          <TraditionalBorder />

          <div className="space-y-4">
            <p className="text-gray-600 italic leading-relaxed text-sm">
              "{data.message}"
            </p>
            {aiQuote ? (
              <div className="py-4 px-6 bg-red-50/50 rounded-2xl border-x-2 border-red-200">
                <p className="text-red-800 text-sm italic font-medium">"{aiQuote}"</p>
              </div>
            ) : (
              <button 
                onClick={handleGenerateQuote}
                className="text-[10px] text-red-500 border border-red-200 rounded-full px-4 py-1 hover:bg-red-50 transition-colors uppercase tracking-widest font-bold"
              >
                {loadingQuote ? '...' : '✨ Tạo cảm hứng tình yêu'}
              </button>
            )}
          </div>
        </div>
      </section>

      {/* Save The Date / Event Info */}
      <section className="bg-red-600 text-white rounded-t-[50px] py-20 px-8">
        <div className="text-center mb-12">
          <h2 className="text-4xl font-wedding mb-2">Save The Date</h2>
          <div className="h-[2px] w-16 bg-white/30 mx-auto"></div>
        </div>

        <div className="grid grid-cols-1 gap-10">
          <div className="glass-card rounded-3xl p-8 text-center text-gray-800 relative overflow-hidden">
             <div className="absolute top-0 right-0 p-4 opacity-10">
                <svg className="w-20 h-20" fill="currentColor" viewBox="0 0 24 24"><path d="M19 4h-1V2h-2v2H8V2H6v2H5c-1.11 0-1.99.9-1.99 2L3 20c0 1.1.89 2 2 2h14c1.1 0 2-.9 2-2V6c0-1.1-.9-2-2-2zm0 16H5V10h14v10zm0-12H5V6h14v2z"/></svg>
             </div>
             <p className="text-red-600 uppercase tracking-widest text-[10px] font-bold mb-2">Save our date</p>
             <p className="text-4xl font-serif-elegant mb-2">25.12.2025</p>
             <p className="text-lg font-medium border-t border-gray-100 pt-4 mt-4">Vào lúc {data.time}</p>
          </div>

          <div className="glass-card rounded-3xl p-8 text-gray-800">
             <div className="flex items-center gap-4 mb-6">
                <div className="bg-red-500 text-white p-3 rounded-2xl shadow-lg">
                   <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                </div>
                <div>
                   <h3 className="text-xl font-bold">{data.location}</h3>
                   <p className="text-xs text-gray-500 uppercase tracking-wider">Hôn lễ cử hành tại</p>
                </div>
             </div>
             <p className="text-sm text-gray-600 leading-relaxed mb-6">{data.locationDetails}</p>
             <a 
               href={data.mapUrl} 
               target="_blank" 
               className="block w-full text-center py-3 bg-red-600 text-white rounded-xl font-bold shadow-md hover:bg-red-700 transition-all"
             >
               Chỉ Đường →
             </a>
          </div>
        </div>

        {/* Countdown */}
        <div className="mt-16 flex justify-between gap-2">
          {[
            { l: 'Ngày', v: timeLeft.d },
            { l: 'Giờ', v: timeLeft.h },
            { l: 'Phút', v: timeLeft.m },
            { l: 'Giây', v: timeLeft.s },
          ].map((t, idx) => (
            <div key={idx} className="flex-1 bg-white/10 border border-white/20 backdrop-blur-sm rounded-2xl p-3 text-center">
              <span className="text-2xl font-bold block">{t.v < 10 ? `0${t.v}` : t.v}</span>
              <span className="text-[10px] uppercase opacity-70 font-medium">{t.l}</span>
            </div>
          ))}
        </div>
      </section>

      {/* Gallery Section */}
      <section className="py-24 bg-white">
        <div className="px-8 mb-12 text-center">
          <p className="text-red-500 font-bold uppercase tracking-widest text-[10px] mb-2">Happy Moments</p>
          <h2 className="text-4xl font-wedding text-gray-800">Album Ảnh</h2>
          <FloralDecoration />
        </div>

        <div className="grid grid-cols-2 gap-2 px-2">
          {data.album.map((img, idx) => (
            <div key={idx} className={`overflow-hidden rounded-lg relative group ${idx % 3 === 0 ? 'col-span-2 aspect-[16/10]' : 'aspect-square'}`}>
              <img 
                src={img} 
                alt={`Wedding ${idx}`} 
                className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
              />
              <div className="absolute inset-0 bg-black/10 opacity-0 group-hover:opacity-100 transition-opacity"></div>
            </div>
          ))}
        </div>
      </section>

      {/* RSVP Section */}
      <section id="rsvp" className="py-24 px-8 bg-gray-50">
        <div className="max-w-md mx-auto">
          <div className="text-center mb-12">
            <h2 className="text-4xl font-wedding text-red-600">Xác Nhận Tham Dự</h2>
            <p className="text-gray-400 text-xs mt-2 italic">Sự hiện diện của quý vị là niềm hạnh phúc của chúng tôi</p>
          </div>

          <form onSubmit={handleRsvpSubmit} className="space-y-6">
            <div className="relative">
              <input 
                required
                type="text" 
                placeholder="Tên của bạn"
                value={rsvp.name}
                onChange={e => setRsvp({...rsvp, name: e.target.value})}
                className="w-full bg-white border border-gray-200 rounded-2xl px-6 py-4 focus:outline-none focus:ring-2 focus:ring-red-500 transition-all shadow-sm"
              />
            </div>

            <div className="flex gap-4">
               <button 
                type="button"
                onClick={() => setRsvp({...rsvp, attendance: 'yes'})}
                className={`flex-1 py-4 rounded-2xl font-bold transition-all border ${rsvp.attendance === 'yes' ? 'bg-red-600 text-white border-red-600 shadow-xl' : 'bg-white text-gray-400 border-gray-100'}`}
               >
                 Sẽ Tham Dự
               </button>
               <button 
                type="button"
                onClick={() => setRsvp({...rsvp, attendance: 'no'})}
                className={`flex-1 py-4 rounded-2xl font-bold transition-all border ${rsvp.attendance === 'no' ? 'bg-gray-800 text-white border-gray-800 shadow-xl' : 'bg-white text-gray-400 border-gray-100'}`}
               >
                 Rất Tiếc
               </button>
            </div>

            {rsvp.attendance === 'yes' && (
              <div className="animate-fade-up">
                <label className="block text-[10px] font-bold uppercase text-gray-400 mb-2 ml-4">Số lượng người</label>
                <select 
                  value={rsvp.guests}
                  onChange={e => setRsvp({...rsvp, guests: parseInt(e.target.value)})}
                  className="w-full bg-white border border-gray-200 rounded-2xl px-6 py-4 focus:outline-none focus:ring-2 focus:ring-red-500 transition-all shadow-sm"
                >
                  {[1, 2, 3, 4, 5].map(n => <option key={n} value={n}>{n} người</option>)}
                </select>
              </div>
            )}

            <textarea 
              rows={3}
              placeholder="Lời chúc thân thương..."
              value={rsvp.message}
              onChange={e => setRsvp({...rsvp, message: e.target.value})}
              className="w-full bg-white border border-gray-200 rounded-2xl px-6 py-4 focus:outline-none focus:ring-2 focus:ring-red-500 transition-all shadow-sm"
            />

            <button 
              disabled={submittingRsvp}
              className={`w-full bg-red-600 text-white font-bold py-5 rounded-3xl shadow-2xl hover:bg-red-700 active:scale-[0.98] transition-all uppercase tracking-widest text-sm flex items-center justify-center gap-2 ${submittingRsvp ? 'opacity-70 cursor-not-allowed' : ''}`}
            >
              {submittingRsvp ? (
                <>
                  <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                  Đang gửi...
                </>
              ) : 'Gửi Xác Nhận'}
            </button>
          </form>
        </div>
      </section>

      {/* Gift Section */}
      <section className="py-20 px-8 bg-white border-t border-gray-50">
         <div className="text-center">
            <h2 className="text-3xl font-wedding text-gray-800 mb-6">Mừng Cưới</h2>
            <button 
              onClick={() => setShowGift(!showGift)}
              className="px-8 py-3 bg-red-50 text-red-600 border border-red-100 rounded-full font-bold text-sm hover:bg-red-100 transition-all"
            >
              {showGift ? 'Ẩn thông tin' : 'Gửi lời chúc & Quà tặng'}
            </button>

            {showGift && (
              <div className="mt-10 grid grid-cols-1 gap-6 animate-fade-up">
                <div className="p-6 bg-gray-50 rounded-3xl border border-dashed border-gray-200">
                  <p className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-4">Mừng cho Chú Rể</p>
                  <div className="bg-white p-4 rounded-2xl shadow-sm text-left">
                    <p className="text-sm font-bold text-gray-800">{data.bankGroom?.bankName}</p>
                    <p className="text-xl font-mono text-red-600 my-1">{data.bankGroom?.accountNumber}</p>
                    <p className="text-[10px] text-gray-400 uppercase tracking-tight">Chủ TK: {data.bankGroom?.accountHolder}</p>
                  </div>
                </div>
                <div className="p-6 bg-gray-50 rounded-3xl border border-dashed border-gray-200">
                  <p className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-4">Mừng cho Cô Dâu</p>
                  <div className="bg-white p-4 rounded-2xl shadow-sm text-left">
                    <p className="text-sm font-bold text-gray-800">{data.bankBride?.bankName}</p>
                    <p className="text-xl font-mono text-red-600 my-1">{data.bankBride?.accountNumber}</p>
                    <p className="text-[10px] text-gray-400 uppercase tracking-tight">Chủ TK: {data.bankBride?.accountHolder}</p>
                  </div>
                </div>
              </div>
            )}
         </div>
      </section>

      {/* Footer */}
      <footer className="py-20 bg-gray-50 text-center px-12">
        <div className="flex justify-center mb-6">
           <HeartIcon className="text-red-200 w-10 h-10" />
        </div>
        <p className="text-3xl font-wedding text-red-600 mb-4">Cảm ơn bạn rất nhiều!</p>
        <p className="text-gray-400 text-[11px] leading-loose tracking-widest uppercase font-medium">
          Hẹn gặp lại bạn tại buổi tiệc <br/> hạnh phúc của chúng tôi
        </p>
        <div className="mt-12 h-[1px] w-20 bg-gray-200 mx-auto"></div>
      </footer>

      {/* Success Modal */}
      {showRsvpSuccess && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-6">
          <div className="bg-white rounded-3xl p-10 text-center shadow-2xl animate-fade-up max-w-sm w-full">
            <div className="w-20 h-20 bg-green-50 text-green-500 rounded-full flex items-center justify-center mx-auto mb-6">
              <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg>
            </div>
            <h3 className="text-2xl font-bold mb-2">Đã Nhận!</h3>
            <p className="text-gray-500 text-sm">Cảm ơn bạn đã xác nhận tham dự. Chúng mình rất mong chờ được đón tiếp bạn!</p>
            <button 
              onClick={() => setShowRsvpSuccess(false)}
              className="mt-8 w-full py-4 bg-gray-100 rounded-2xl text-gray-600 font-bold hover:bg-gray-200 transition-all"
            >
              Tuyệt Vời
            </button>
          </div>
        </div>
      )}
    </div>
