import React, { useState, useEffect } from 'react';
import { WeddingData, RSVP } from './types';
import { DEFAULT_WEDDING_DATA, HeartIcon, ModernDivider, CONFIG } from './constants';
import { generateWeddingQuote } from './geminiService';

const App: React.FC = () => {
  const [data] = useState<WeddingData>(DEFAULT_WEDDING_DATA);
  const [aiQuote, setAiQuote] = useState<string>("");
  const [loadingQuote, setLoadingQuote] = useState(false);
  const [submittingRsvp, setSubmittingRsvp] = useState(false);
  const [rsvp, setRsvp] = useState<RSVP>({ name: '', attendance: 'yes', guests: 1, message: '' });
  const [showRsvpSuccess, setShowRsvpSuccess] = useState(false);
  const [showGift, setShowGift] = useState(false);
  const [timeLeft, setTimeLeft] = useState({ d: 0, h: 0, m: 0, s: 0 });

  useEffect(() => {
    const target = new Date(data.date).getTime();
    const interval = setInterval(() => {
      const now = new Date().getTime();
      const distance = target - now;
      if (distance < 0) {
        clearInterval(interval);
        return;
      }
      setTimeLeft({
        d: Math.floor(distance / (1000 * 60 * 60 * 24)),
        h: Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
        m: Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60)),
        s: Math.floor((distance % (1000 * 60)) / 1000)
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [data.date]);

  const handleGenerateQuote = async () => {
    if (loadingQuote) return;
    setLoadingQuote(true);
    const quote = await generateWeddingQuote(data.groomName, data.brideName);
    setAiQuote(quote);
    setLoadingQuote(false);
  };

  const handleRsvpSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmittingRsvp(true);

    if (CONFIG.useTelegram && CONFIG.telegramToken && CONFIG.telegramChatId) {
      const text = `🔔 *THÔNG BÁO XÁC NHẬN*\n\n👤 Khách: ${rsvp.name}\n✅ Trạng thái: ${rsvp.attendance === 'yes' ? 'THAM DỰ' : 'KHÔNG THỂ'}\n👥 Số người: ${rsvp.guests}\n💬 Lời chúc: ${rsvp.message}`;
      try {
        await fetch(`https://api.telegram.org/bot${CONFIG.telegramToken}/sendMessage`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ chat_id: CONFIG.telegramChatId, text, parse_mode: 'Markdown' })
        });
      } catch (error) { console.error(error); }
    }

    setTimeout(() => {
      setSubmittingRsvp(false);
      setShowRsvpSuccess(true);
      setRsvp({ name: '', attendance: 'yes', guests: 1, message: '' });
    }, 1000);
  };

  return (
    <div className="min-h-screen max-w-[500px] mx-auto bg-white shadow-2xl relative">

      {/* SECTION 1: HERO - Minimalist Style */}
      <section className="relative h-[100vh] flex flex-col items-center justify-between py-20 px-6 overflow-hidden bg-white">
        <div className="absolute inset-0 z-0">
          <img 
            src={data.heroImage} 
            alt="Main" 
            className="w-full h-full object-cover grayscale-[20%] opacity-90"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-white via-white/20 to-transparent"></div>
        </div>

        <div className="relative z-10 text-center animate-fade-up">
          <p className="text-[10px] letter-spacing-widest uppercase mb-4 text-gray-500 font-medium">Save our date</p>
          <div className="space-y-2">
            <h1 className="text-5xl font-serif-elegant tracking-tight text-gray-800">{data.groomName.split(' ').pop()}</h1>
            <p className="text-3xl font-wedding text-red-400">&</p>
            <h1 className="text-5xl font-serif-elegant tracking-tight text-gray-800">{data.brideName.split(' ').pop()}</h1>
          </div>
        </div>

        <div className="relative z-10 text-center animate-fade-up" style={{animationDelay: '0.3s'}}>
          <p className="text-sm font-serif-elegant italic mb-1 text-gray-600">Tháng 12, Ngày 25</p>
          <p className="text-4xl font-serif-elegant tracking-[0.2em] text-gray-900">2025</p>
        </div>
      </section>

      {/* SECTION 2: THE INVITATION - White Clean Block */}
      <section className="py-24 px-10 text-center bg-silk">
        <div className="space-y-10 animate-fade-up">
          <h2 className="text-xs letter-spacing-widest uppercase text-gray-400 font-bold">Invitation</h2>
          <div className="space-y-4">
            <p className="text-gray-500 text-sm leading-relaxed px-4 italic font-serif-elegant">
              "{data.message}"
            </p>
            <ModernDivider />
          </div>

          <div className="grid grid-cols-1 gap-12 text-gray-800">
            <div>
              <p className="text-xs uppercase text-gray-400 mb-2">Groom's Family</p>
              <h3 className="text-lg font-serif-elegant font-bold">{data.groomName}</h3>
              <div className="mt-2 text-xs text-gray-500 space-y-1">
                <p>Ông: {data.groomFather}</p>
                <p>Bà: {data.groomMother}</p>
              </div>
            </div>

            <HeartIcon className="mx-auto text-gray-200" />

            <div>
              <p className="text-xs uppercase text-gray-400 mb-2">Bride's Family</p>
              <h3 className="text-lg font-serif-elegant font-bold">{data.brideName}</h3>
              <div className="mt-2 text-xs text-gray-500 space-y-1">
                <p>Ông: {data.brideFather}</p>
                <p>Bà: {data.brideMother}</p>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* SECTION 3: TIMELINE - Event Details */}
      <section className="py-24 px-8 bg-gray-50/50">
        <div className="text-center mb-16">
          <h2 className="text-3xl font-wedding text-gray-800 mb-2">Wedding Events</h2>
          <div className="h-px w-10 bg-gray-300 mx-auto"></div>
        </div>

        <div className="space-y-8">
          {/* Event 1 */}
          <div className="bg-white p-8 rounded-[2rem] shadow-soft border border-gray-100 flex flex-col items-center text-center">
            <div className="w-12 h-12 bg-gray-50 rounded-full flex items-center justify-center mb-6">
              <svg className="w-6 h-6 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>
            </div>
            <h4 className="text-sm uppercase tracking-widest font-bold text-gray-800 mb-2">Lễ Thành Hôn</h4>
            <p className="text-2xl font-serif-elegant text-gray-900 mb-4">11:00 AM</p>
            <p className="text-xs text-gray-500 leading-relaxed mb-6">{data.locationDetails}</p>
            <a href={data.mapUrl} target="_blank" className="text-[10px] uppercase font-bold text-red-400 tracking-widest border-b border-red-100 pb-1">Xem bản đồ</a>
          </div>

          {/* Event 2 */}
          <div className="bg-white p-8 rounded-[2rem] shadow-soft border border-gray-100 flex flex-col items-center text-center">
            <div className="w-12 h-12 bg-gray-50 rounded-full flex items-center justify-center mb-6">
              <svg className="w-6 h-6 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M21 15.546c.533-1.341.83-2.77.83-4.262 0-4.418-3.582-8-8-8s-8 3.582-8 8c0 1.492.297 2.921.83 4.262L3 21l3.325-1.127a7.99 7.99 0 005.175.627A8.005 8.005 0 0021 15.546z" /></svg>
            </div>
            <h4 className="text-sm uppercase tracking-widest font-bold text-gray-800 mb-2">Tiệc Chiêu Đãi</h4>
            <p className="text-2xl font-serif-elegant text-gray-900 mb-4">12:30 PM</p>
            <p className="text-xs text-gray-500 leading-relaxed mb-6">{data.location}</p>
            <p className="text-[10px] uppercase font-bold text-gray-400 tracking-widest">Trân trọng kính mời</p>
          </div>
        </div>
      </section>

      {/* SECTION 4: GALLERY - Modern Masonry */}
      <section className="py-24 bg-white">
        <div className="px-10 mb-12">
          <h2 className="text-3xl font-wedding text-gray-800">Photo Gallery</h2>
          <p className="text-[10px] text-gray-400 uppercase tracking-widest mt-2">Beautiful moments of us</p>
        </div>
        <div className="px-4 columns-2 gap-4 space-y-4">
          {data.album.map((img, idx) => (
            <div key={idx} className="overflow-hidden rounded-2xl shadow-soft">
              <img src={img} alt="Gallery" className="w-full h-auto hover:scale-105 transition-transform duration-1000" />
            </div>
          ))}
        </div>
      </section>

      {/* SECTION 5: COUNTDOWN - Styled Box */}
      <section className="py-20 px-10 bg-black text-white text-center">
        <h3 className="text-xs uppercase letter-spacing-widest mb-10 opacity-60 font-bold">Countdown to our forever</h3>
        <div className="flex justify-between max-w-[300px] mx-auto">
          {[
            { label: 'Days', value: timeLeft.d },
            { label: 'Hrs', value: timeLeft.h },
            { label: 'Mins', value: timeLeft.m },
            { label: 'Secs', value: timeLeft.s }
          ].map((item, i) => (
            <div key={i} className="flex flex-col items-center">
              <span className="text-3xl font-serif-elegant mb-1">{item.value < 10 ? `0${item.value}` : item.value}</span>
              <span className="text-[8px] uppercase tracking-widest opacity-40">{item.label}</span>
            </div>
          ))}
        </div>
      </section>

      {/* SECTION 6: RSVP - Floating Card */}
      <section className="py-32 px-6 bg-gray-50 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-red-50/30 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2"></div>
        <div className="relative z-10 bg-white rounded-[3rem] p-10 shadow-soft border border-gray-100 max-w-sm mx-auto">
          <div className="text-center mb-10">
            <h2 className="text-3xl font-wedding text-gray-800 mb-2">RSVP</h2>
            <p className="text-[10px] text-gray-400 uppercase tracking-widest">Xác nhận tham dự</p>
          </div>

          <form onSubmit={handleRsvpSubmit} className="space-y-6">
            <input 
              required
              placeholder="Họ và tên của bạn"
              value={rsvp.name}
              onChange={e => setRsvp({...rsvp, name: e.target.value})}
              className="w-full border-b border-gray-100 py-3 px-2 focus:outline-none focus:border-gray-400 transition-colors bg-transparent text-sm"
            />

            <div className="flex gap-4">
              <button 
                type="button"
                onClick={() => setRsvp({...rsvp, attendance: 'yes'})}
                className={`flex-1 text-[10px] uppercase font-bold py-3 rounded-full transition-all tracking-widest ${rsvp.attendance === 'yes' ? 'bg-gray-900 text-white shadow-lg' : 'bg-gray-50 text-gray-400'}`}
              >Tham dự</button>
              <button 
                type="button"
                onClick={() => setRsvp({...rsvp, attendance: 'no'})}
                className={`flex-1 text-[10px] uppercase font-bold py-3 rounded-full transition-all tracking-widest ${rsvp.attendance === 'no' ? 'bg-gray-900 text-white shadow-lg' : 'bg-gray-50 text-gray-400'}`}
              >Rất tiếc</button>
            </div>

            {rsvp.attendance === 'yes' && (
              <select 
                value={rsvp.guests}
                onChange={e => setRsvp({...rsvp, guests: parseInt(e.target.value)})}
                className="w-full border-b border-gray-100 py-3 px-2 focus:outline-none bg-transparent text-sm text-gray-500"
              >
                {[1, 2, 3, 4, 5].map(n => <option key={n} value={n}>{n} người</option>)}
              </select>
            )}

            <textarea 
              placeholder="Lời chúc thân tình..."
              value={rsvp.message}
              onChange={e => setRsvp({...rsvp, message: e.target.value})}
              className="w-full border border-gray-50 bg-gray-50/50 rounded-2xl p-4 text-sm focus:outline-none focus:ring-1 focus:ring-gray-200"
              rows={3}
            />

            <button 
              disabled={submittingRsvp}
              className="w-full bg-red-400 text-white text-[10px] uppercase font-bold tracking-[0.2em] py-5 rounded-2xl shadow-xl hover:bg-red-500 active:scale-[0.98] transition-all"
            >
              {submittingRsvp ? 'Đang gửi...' : 'Gửi thông tin'}
            </button>
          </form>
        </div>
      </section>

      {/* SECTION 7: GIFT - Minimal Drawer */}
      <section className="py-20 text-center px-10">
        <h3 className="text-3xl font-wedding mb-6">Wedding Gift</h3>
        <p className="text-xs text-gray-400 mb-10 leading-relaxed italic">"Tình cảm của bạn là món quà quý giá nhất, nhưng nếu bạn muốn gửi lời chúc thiết thực hơn..."</p>
        <button 
          onClick={() => setShowGift(!showGift)}
          className="bg-white border border-gray-100 px-8 py-3 rounded-full text-[10px] uppercase font-bold tracking-widest text-gray-500 shadow-soft hover:shadow-lg transition-all"
        >
          {showGift ? 'Đóng thông tin' : 'Gửi quà cưới'}
        </button>

        {showGift && (
          <div className="mt-12 grid grid-cols-1 gap-6 animate-fade-up">
            <div className="bg-gray-50/50 p-8 rounded-[2.5rem] border border-gray-100">
               <p className="text-[10px] uppercase tracking-widest text-gray-400 mb-6 font-bold">Chú Rể</p>
               <p className="text-sm font-bold text-gray-800 mb-1">{data.bankGroom?.bankName}</p>
               <p className="text-xl font-serif-elegant tracking-widest text-red-400">{data.bankGroom?.accountNumber}</p>
               <p className="text-[9px] uppercase tracking-tighter text-gray-400 mt-2">{data.bankGroom?.accountHolder}</p>
            </div>
            <div className="bg-gray-50/50 p-8 rounded-[2.5rem] border border-gray-100">
               <p className="text-[10px] uppercase tracking-widest text-gray-400 mb-6 font-bold">Cô Dâu</p>
               <p className="text-sm font-bold text-gray-800 mb-1">{data.bankBride?.bankName}</p>
               <p className="text-xl font-serif-elegant tracking-widest text-red-400">{data.bankBride?.accountNumber}</p>
               <p className="text-[9px] uppercase tracking-tighter text-gray-400 mt-2">{data.bankBride?.accountHolder}</p>
            </div>
          </div>
        )}
      </section>

      {/* FOOTER */}
      <footer className="py-24 bg-white text-center">
        <HeartIcon className="mx-auto text-red-100 w-12 h-12 mb-8" />
        <h4 className="text-4xl font-wedding text-gray-800 mb-4">Cảm ơn bạn!</h4>
        <p className="text-[10px] uppercase tracking-widest text-gray-400">See you at the party</p>
      </footer>

      {/* MODAL SUCCESS */}
      {showRsvpSuccess && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-white/90 backdrop-blur-md p-6">
          <div className="text-center animate-fade-up max-w-xs">
            <div className="text-4xl mb-6">✨</div>
