import React, { useState, useEffect } from 'react';
import { WeddingData, RSVP } from './types';
import { DEFAULT_WEDDING_DATA, HeartIcon, ClassicHySymbol, DecorativeBorder, CONFIG } from './constants';

const App: React.FC = () => {
  const [data] = useState<WeddingData>(DEFAULT_WEDDING_DATA);
  const [isOpening, setIsOpening] = useState(false);
  const [hasOpened, setHasOpened] = useState(false);
  const [submittingRsvp, setSubmittingRsvp] = useState(false);
  const [rsvp, setRsvp] = useState<RSVP>({ name: '', attendance: 'yes', guests: 1, message: '' });
  const [showRsvpSuccess, setShowRsvpSuccess] = useState(false);
  const [showGift, setShowGift] = useState(false);
  const [timeLeft, setTimeLeft] = useState({ d: 0, h: 0, m: 0, s: 0 });

  useEffect(() => {
    // Tự động mở thiệp sau 800ms khi vào trang
    const timer = setTimeout(() => {
      setIsOpening(true);
    }, 800);

    // Sau khi animation hoàn tất (1.8s + 0.8s delay), set trạng thái đã mở hẳn
    const timer2 = setTimeout(() => {
      setHasOpened(true);
    }, 3000);

    const target = new Date(data.date).getTime();
    const interval = setInterval(() => {
      const now = new Date().getTime();
      const distance = target - now;
      if (distance < 0) {
        clearInterval(interval);
        return;
      }
      setTimeLeft({
        d: Math.floor(distance / (1000 * 60 * 60 * 24)),
        h: Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
        m: Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60)),
        s: Math.floor((distance % (1000 * 60)) / 1000)
      });
    }, 1000);

    return () => {
      clearTimeout(timer);
      clearTimeout(timer2);
      clearInterval(interval);
    };
  }, [data.date]);

  const handleRsvpSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmittingRsvp(true);

    if (CONFIG.useTelegram && CONFIG.telegramToken && CONFIG.telegramChatId) {
      const text = `🔔 *XÁC NHẬN THAM DỰ*\n\n👤 Khách: ${rsvp.name}\n✅ Tham gia: ${rsvp.attendance === 'yes' ? 'CÓ' : 'KHÔNG'}\n👥 Số người: ${rsvp.guests}\n💬 Lời chúc: ${rsvp.message}`;
      try {
        await fetch(`https://api.telegram.org/bot${CONFIG.telegramToken}/sendMessage`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ chat_id: CONFIG.telegramChatId, text, parse_mode: 'Markdown' })
        });
      } catch (error) { console.error(error); }
    }

    setTimeout(() => {
      setSubmittingRsvp(false);
      setShowRsvpSuccess(true);
      setRsvp({ name: '', attendance: 'yes', guests: 1, message: '' });
    }, 1000);
  };

  return (
    <div className={`min-h-screen max-w-[500px] mx-auto bg-white shadow-luxury relative ${!hasOpened ? 'overflow-hidden h-screen' : ''}`}>

      {/* --- HIỆU ỨNG CÁNH THIỆP MỞ ĐẦU --- */}
      {!hasOpened && (
        <div className={`fixed inset-0 z-[200] flex max-w-[500px] mx-auto ${isOpening ? 'doors-open' : ''}`}>
          {/* Cánh trái */}
          <div className="door-left w-1/2 h-full bg-velvet-door border-r border-yellow-200/20 flex items-center justify-end overflow-hidden">
             <div className="translate-x-1/2 text-7xl gold-text font-serif animate-shimmer">
                囍
             </div>
          </div>
          {/* Cánh phải */}
          <div className="door-right w-1/2 h-full bg-velvet-door border-l border-yellow-200/20 flex items-center justify-start overflow-hidden">
             <div className="-translate-x-1/2 text-7xl gold-text font-serif animate-shimmer">
                囍
             </div>
          </div>
          {/* Lớp phủ nhung mờ */}
          <div className={`absolute inset-0 bg-red-950/20 pointer-events-none transition-opacity duration-1000 ${isOpening ? 'opacity-0' : 'opacity-100'}`}></div>
        </div>
      )}

      {/* --- PHẦN 1: HERO SECTION (Ảnh bìa lộ ra sau cánh thiệp) --- */}
      <section className="relative h-screen w-full overflow-hidden flex flex-col items-center justify-center text-white">
        <div className="absolute inset-0 z-0">
          <img 
            src={data.heroImage} 
            alt="Wedding Hero" 
            className={`w-full h-full object-cover transition-transform duration-[3s] ${isOpening ? 'scale-110' : 'scale-125'} grayscale-[10%]`}
          />
          <div className="absolute inset-0 bg-gradient-to-b from-black/50 via-transparent to-black/70"></div>
        </div>

        <div className={`relative z-10 text-center px-6 transition-all duration-1000 delay-700 ${isOpening ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10'}`}>
          <div className="mb-6">
            <p className="text-[10px] tracking-[0.5em] uppercase font-bold text-white/80 mb-2">Save our date</p>
            <div className="h-px w-20 bg-yellow-200/30 mx-auto"></div>
          </div>

          <div className="space-y-4">
            <h1 className="text-8xl font-wedding gold-text tracking-wider leading-none drop-shadow-2xl">
              {data.groomName.split(' ').pop()}
            </h1>
            <p className="text-3xl font-calligraphy text-yellow-100/40 italic leading-none">&</p>
            <h1 className="text-8xl font-wedding gold-text tracking-wider leading-none drop-shadow-2xl">
              {data.brideName.split(' ').pop()}
            </h1>
          </div>

          <div className="mt-14">
            <p className="text-xl font-serif-elegant tracking-[0.4em] font-light uppercase border-y border-white/10 py-3 inline-block px-8">
              {data.date.split('-').reverse().join(' . ')}
            </p>
          </div>

          <div className="absolute bottom-12 left-1/2 -translate-x-1/2 animate-bounce opacity-40">
             <p className="text-[8px] uppercase tracking-[0.3em] mb-2 font-bold">Cuộn xuống để xem tiếp</p>
             <svg className="w-5 h-5 mx-auto" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 13l-7 7-7-7" /></svg>
          </div>
        </div>
      </section>

      {/* --- PHẦN 2: THƯ NGỎ (Bay bướm hơn) --- */}
      <section className="py-32 px-10 text-center bg-white relative">
        <div className="absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 z-20">
          <div className="w-16 h-16 bg-white rounded-full shadow-xl flex items-center justify-center border border-red-50">
            <HeartIcon className="text-red-600 animate-pulse" />
          </div>
        </div>

        <div className="space-y-12">
          <div className="space-y-6">
            <h2 className="text-[10px] tracking-[0.6em] uppercase font-bold text-red-800">Lời Ngỏ</h2>
            <p className="text-4xl font-wedding text-gray-700 leading-snug px-2">
              {data.message}
            </p>
            <DecorativeBorder />
          </div>
        </div>
      </section>

      {/* --- PHẦN 3: GIA ĐÌNH --- */}
      <section className="py-24 px-8 bg-gray-50/50 border-y border-red-50">
        <div className="grid grid-cols-1 gap-24">
          <div className="text-center space-y-8">
            <div className="space-y-2">
              <p className="text-[9px] uppercase tracking-[0.4em] text-gray-400 font-bold">Gia Đình Nhà Trai</p>
              <p className="text-xs text-gray-500 font-medium italic">Ông: {data.groomFather}</p>
              <p className="text-xs text-gray-500 font-medium italic">Bà: {data.groomMother}</p>
            </div>
            <h3 className="text-7xl font-wedding text-red-900 tracking-wider">{data.groomName}</h3>
          </div>

          <div className="flex justify-center items-center py-4">
            <div className="h-px w-20 bg-red-100"></div>
            <HeartIcon className="mx-6 text-red-200 w-10 h-10 animate-pulse-slow" />
            <div className="h-px w-20 bg-red-100"></div>
          </div>

          <div className="text-center space-y-8">
