              <p className="text-[9px] uppercase tracking-[0.4em] text-gray-400 font-bold">Gia Đình Nhà Gái</p>
              <p className="text-xs text-gray-500 font-medium italic">Ông: {data.brideFather}</p>
              <p className="text-xs text-gray-500 font-medium italic">Bà: {data.brideMother}</p>
            </div>
            <h3 className="text-7xl font-wedding text-red-900 tracking-wider">{data.brideName}</h3>
          </div>
