        <div className="text-center mb-24">
          <h2 className="text-6xl font-wedding gold-text">Tiệc Cưới</h2>
          <div className="h-px w-16 bg-yellow-200/20 mx-auto mt-6"></div>
        </div>

        <div className="space-y-12">
          <div className="bg-white/5 backdrop-blur-xl border border-white/10 p-14 rounded-[3rem] text-center space-y-6">
            <h4 className="text-[10px] tracking-[0.6em] uppercase font-bold text-yellow-100/60">Lễ Thành Hôn</h4>
            <p className="text-6xl font-serif-elegant gold-text font-bold tracking-tighter">{data.time}</p>
            <p className="text-sm font-serif-elegant italic text-yellow-50/80 uppercase tracking-[0.3em]">{data.date.split('-').reverse().join(' . ')}</p>
            <div className="w-12 h-px bg-white/10 mx-auto my-8"></div>
            <p className="text-xs font-medium uppercase tracking-[0.2em] text-white/70 leading-relaxed px-6">{data.locationDetails}</p>
            <a href={data.mapUrl} target="_blank" className="inline-block mt-10 px-14 py-4 rounded-full border border-yellow-200/20 text-[10px] uppercase font-bold tracking-[0.3em] hover:bg-white hover:text-red-900 transition-all duration-500">Xem bản đồ</a>
          </div>

          <div className="bg-white p-14 rounded-[3rem] text-center space-y-6 shadow-2xl">
            <h4 className="text-[10px] tracking-[0.6em] uppercase font-bold text-gray-400">Tiệc Chiêu Đãi</h4>
