  const [isOpening, setIsOpening] = useState(false);
  const [hasOpened, setHasOpened] = useState(false);
  const [submittingRsvp, setSubmittingRsvp] = useState(false);
  const [rsvp, setRsvp] = useState<RSVP>({ name: '', attendance: 'yes', guests: 1, message: '' });
  const [showRsvpSuccess, setShowRsvpSuccess] = useState(false);
  const [showGift, setShowGift] = useState(false);
  const [timeLeft, setTimeLeft] = useState({ d: 0, h: 0, m: 0, s: 0 });

  useEffect(() => {
    const timerOpen = setTimeout(() => {
      setIsOpening(true);
    }, 500);

    const timerFinish = setTimeout(() => {
      setHasOpened(true);
    }, 2800);

    const target = new Date(data.date).getTime();
    const interval = setInterval(() => {
      const now = new Date().getTime();
      const distance = target - now;
      if (distance < 0) {
        clearInterval(interval);
        return;
      }
      setTimeLeft({
        d: Math.floor(distance / (1000 * 60 * 60 * 24)),
        h: Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
        m: Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60)),
        s: Math.floor((distance % (1000 * 60)) / 1000)
      });
    }, 1000);

    return () => {
      clearTimeout(timerOpen);
      clearTimeout(timerFinish);
      clearInterval(interval);
    };
  }, [data.date]);

  const handleRsvpSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmittingRsvp(true);
    setTimeout(() => {
      setSubmittingRsvp(false);
      setShowRsvpSuccess(true);
      setRsvp({ name: '', attendance: 'yes', guests: 1, message: '' });
    }, 1000);
  };

