            <div className="translate-x-1/2 gold-text text-8xl animate-gold">囍</div>
          </div>
          <div className="door-right w-1/2 h-full bg-red-velvet border-l border-yellow-200/20 flex items-center justify-start">
            <div className="-translate-x-1/2 gold-text text-8xl animate-gold">囍</div>
          </div>
