        {/* Background Image */}
        <div className="absolute inset-0 z-0">
          <img 
            src={data.heroImage} 
            className={`w-full h-full object-cover object-center transition-transform duration-[10s] ${isOpening ? 'scale-100' : 'scale-110'}`} 
            alt="Hero" 
