        <div className="relative z-10 space-y-10">
          <div className="bg-white/5 backdrop-blur-xl border border-white/10 p-12 rounded-[3rem] text-center space-y-8">
            <h4 className="text-[10px] tracking-[0.6em] uppercase font-bold text-yellow-100/60">Tổ chức tại</h4>
            <p className="text-6xl font-serif-elegant gold-text font-bold tracking-tighter">TƯ GIA</p>
            <div className="space-y-2">
              <p className="text-lg font-serif-elegant italic text-red-50 uppercase tracking-[0.2em]">08:30 AM</p>
              <p className="text-sm font-light text-red-100/70">Thứ Năm, 26 tháng 02 năm 2026</p>
              <p className="text-xs italic text-yellow-100/40">(Nhằm ngày 10 tháng 01 năm Bính Ngọ)</p>
            </div>
            <div className="w-12 h-px bg-white/10 mx-auto my-6"></div>
